import{_ as t,o as e,c as r,a3 as s}from"./chunks/framework.CS9vaShW.js";const g=JSON.parse('{"title":"金融市场日报：2026-07-13｜油价冲击重启全球再通胀交易","description":"过去24小时，海湾冲突与霍尔木兹海峡通行风险推动油价、美元和国债收益率同步上行，全球股票市场重新交易通胀与利率上行风险。","frontmatter":{"title":"金融市场日报：2026-07-13｜油价冲击重启全球再通胀交易","date":"2026-07-13 09:46:25 +08:00","slug":"daliy-post-20260713","category":"每日记录","tags":["金融","宏观经济","量化交易","美股","全球股市","每日记录"],"description":"过去24小时，海湾冲突与霍尔木兹海峡通行风险推动油价、美元和国债收益率同步上行，全球股票市场重新交易通胀与利率上行风险。","wordCount":3158},"headers":[],"relativePath":"posts/daliy-post-20260713.md","filePath":"posts/daliy-post-20260713.md","lastUpdated":1784048876000}'),l={name:"posts/daliy-post-20260713.md"};function i(o,a,n,d,u,h){return e(),r("div",null,[...a[0]||(a[0]=[s('<blockquote><p>信息窗口：2026-07-12 09:46 至 2026-07-13 09:46（上海时间）。仅收录在该窗口内发布或发生实质更新、且标题、作者、来源、发布时间与原文地址可核验的内容。</p></blockquote><h2 id="今日摘要" tabindex="-1">今日摘要 <a class="header-anchor" href="#今日摘要" aria-label="Permalink to &quot;今日摘要&quot;">​</a></h2><ul><li>海湾冲突升级与霍尔木兹海峡通行风险成为过去24小时最重要的跨资产驱动因素，布伦特原油在亚洲早盘上涨约3.3%，重新激活全球再通胀交易。</li><li>油价上涨并未触发典型的“债券避险上涨”，反而推动美国国债收益率和美元同步走强，说明市场当前更关注能源冲击对通胀与央行政策的二阶影响。</li><li>联邦基金期货进一步提高了年内加息预期，美股尤其是高久期成长股面临“盈利预期仍强、估值折现率上升”的双向拉扯。</li><li>亚洲股市总体承压，日本、韩国和区域指数走弱；韩国半导体板块的杠杆交易退潮仍可能向全球科技股扩散。</li><li>印度等能源进口型经济体同时面临本币、债券与通胀压力，油价持续性将决定新兴市场资产是否从局部波动转向系统性风险重定价。</li><li>严格24小时窗口内未发现可完整核验的新量化交易论文或监管研究，本期不以旧文补位，重点记录可由当前行情直接推导的模型、执行与风控含义。</li></ul><h2 id="金融市场" tabindex="-1">金融市场 <a class="header-anchor" href="#金融市场" aria-label="Permalink to &quot;金融市场&quot;">​</a></h2><h3 id="shares-slip-in-asia-as-oil-jumps-on-gulf-attacks" tabindex="-1"><a href="https://www.reuters.com/business/media-telecom/global-markets-global-markets-2026-07-13/" target="_blank" rel="noreferrer">Shares slip in Asia as oil jumps on Gulf attacks</a> <a class="header-anchor" href="#shares-slip-in-asia-as-oil-jumps-on-gulf-attacks" aria-label="Permalink to &quot;[Shares slip in Asia as oil jumps on Gulf attacks](https://www.reuters.com/business/media-telecom/global-markets-global-markets-2026-07-13/)&quot;">​</a></h3><ul><li><strong>作者或机构：</strong> Wayne Cole</li><li><strong>来源媒体：</strong> Reuters</li><li><strong>发布时间：</strong> 2026-07-13 00:25 UTC（上海时间 08:25）</li><li><strong>核心观点：</strong> 海湾冲突升级及伊朗声称关闭霍尔木兹海峡，推动布伦特原油上涨约3.3%至每桶78.50美元，美国原油上涨约3.4%。亚洲股市、标普500期货和纳斯达克期货走弱，美国10年期国债收益率升至约4.59%，美元走强，黄金则受到实际利率和美元压力。</li><li><strong>为什么值得阅读：</strong> 文章提供了同一时间截面下股票、原油、利率、美元和黄金的联动，是判断当前市场究竟在交易“避险”还是“再通胀”的关键材料。</li><li><strong>市场与策略影响：</strong> 当前冲击表现为油价上涨、收益率上涨、美元上涨、成长股承压，属于再通胀型风险厌恶，而非传统衰退型避险。组合层面应降低对“股跌债涨”负相关关系的机械依赖，并重新测试能源冲击下的跨资产相关性。</li></ul><h2 id="宏观经济" tabindex="-1">宏观经济 <a class="header-anchor" href="#宏观经济" aria-label="Permalink to &quot;宏观经济&quot;">​</a></h2><h3 id="dollar-jumps-on-renewed-middle-east-attacks-hormuz-closure" tabindex="-1"><a href="https://www.reuters.com/world/asia-pacific/dollar-jumps-renewed-middle-east-attacks-hormuz-closure-2026-07-13/" target="_blank" rel="noreferrer">Dollar jumps on renewed Middle East attacks, Hormuz closure</a> <a class="header-anchor" href="#dollar-jumps-on-renewed-middle-east-attacks-hormuz-closure" aria-label="Permalink to &quot;[Dollar jumps on renewed Middle East attacks, Hormuz closure](https://www.reuters.com/world/asia-pacific/dollar-jumps-renewed-middle-east-attacks-hormuz-closure-2026-07-13/)&quot;">​</a></h3><ul><li><strong>作者或机构：</strong> Gregor Stuart Hunter</li><li><strong>来源媒体：</strong> Reuters</li><li><strong>发布时间：</strong> 2026-07-13 00:29 UTC（上海时间 08:29）</li><li><strong>核心观点：</strong> 中东冲突和油价上涨推高全球通胀担忧，美元对主要货币普遍走强。联邦基金期货显示，市场对美联储在12月前至少加息两次的隐含概率升至52.1%，高于上周五的47.6%。市场将重点关注美国CPI、PPI以及美联储主席 Kevin Warsh 的国会证词。</li><li><strong>为什么值得阅读：</strong> 文章清晰展示了能源价格如何通过通胀预期传导至政策利率预期，再传导至美元与全球金融条件。</li><li><strong>市场与策略影响：</strong> 若油价继续上涨且美国核心通胀未明显回落，美元多头与前端利率上行交易仍有基本面支持；反之，若能源冲击快速消退，当前加息定价可能迅速回撤，利率与美元仓位存在拥挤反转风险。</li></ul><h2 id="量化交易" tabindex="-1">量化交易 <a class="header-anchor" href="#量化交易" aria-label="Permalink to &quot;量化交易&quot;">​</a></h2><h3 id="本窗口未收录新论文或监管研究" tabindex="-1">本窗口未收录新论文或监管研究 <a class="header-anchor" href="#本窗口未收录新论文或监管研究" aria-label="Permalink to &quot;本窗口未收录新论文或监管研究&quot;">​</a></h3><p>严格检索后，未发现同时满足以下条件的新量化交易内容：在过去24小时内发布或实质更新；具备可核验作者、机构、发布时间和原始链接；内容达到论文、监管研究或高质量机构研究标准。因此本期不使用历史论文或二手文章凑数。</p><p><strong>可执行的量化观察：</strong></p><ol><li><strong>相关性状态切换：</strong> 当前表现为原油、美元和美债收益率同涨，股票下跌。应将“能源供给冲击”设为独立市场状态，避免沿用常规风险厌恶状态下股债负相关假设。</li><li><strong>波动率与跳跃风险：</strong> 周末地缘事件在亚洲开盘集中定价，跨周末持仓应提高跳跃风险预算，并对开盘滑点、盘口稀疏与止损穿透进行压力测试。</li><li><strong>半导体因子拥挤：</strong> 韩国市场近期半导体杠杆交易明显降温，可将韩国芯片指数、美国半导体指数、纳斯达克期货之间的领先滞后关系纳入短周期风险监控。</li><li><strong>事件驱动窗口：</strong> 美国CPI、PPI及美联储主席证词临近，模型应降低对地缘新闻单因子的持续性外推，防止宏观数据造成方向反转。</li><li><strong>风险管理：</strong> 建议对原油上涨10%、美元指数上涨1%、10年期美债收益率上升25个基点的联合场景进行组合压力测试，而不是逐因子独立冲击。</li></ol><h2 id="美股" tabindex="-1">美股 <a class="header-anchor" href="#美股" aria-label="Permalink to &quot;美股&quot;">​</a></h2><h3 id="shares-slip-in-asia-as-oil-jumps-on-gulf-attacks-1" tabindex="-1"><a href="https://www.reuters.com/business/media-telecom/global-markets-global-markets-2026-07-13/" target="_blank" rel="noreferrer">Shares slip in Asia as oil jumps on Gulf attacks</a> <a class="header-anchor" href="#shares-slip-in-asia-as-oil-jumps-on-gulf-attacks-1" aria-label="Permalink to &quot;[Shares slip in Asia as oil jumps on Gulf attacks](https://www.reuters.com/business/media-telecom/global-markets-global-markets-2026-07-13/)&quot;">​</a></h3><ul><li><strong>作者或机构：</strong> Wayne Cole</li><li><strong>来源媒体：</strong> Reuters</li><li><strong>发布时间：</strong> 2026-07-13 00:25 UTC（上海时间 08:25）</li><li><strong>核心观点：</strong> 标普500期货下跌约0.3%，纳斯达克期货下跌约0.5%。投资者一方面担忧油价和利率上行，另一方面仍期待大型银行、Netflix 与 GE 等公司的财报支撑盈利预期。科技板块盈利动能仍强，但AI相关资产波动率可能维持高位。</li><li><strong>为什么值得阅读：</strong> 它揭示了美股当前的主要矛盾：盈利增长与AI资本开支仍支撑指数，但更高的油价和折现率正在压缩估值容忍度。</li><li><strong>市场与策略影响：</strong> 高久期科技股对实际利率变化更敏感，短期可能弱于金融、能源和材料等受益于名义增长与商品价格的板块。财报季中应区分盈利上修与估值扩张，避免将指数上涨完全归因于基本面改善。</li></ul><h2 id="全球股票市场" tabindex="-1">全球股票市场 <a class="header-anchor" href="#全球股票市场" aria-label="Permalink to &quot;全球股票市场&quot;">​</a></h2><h3 id="gulf-bourses-subdued-as-us-and-iran-exchange-strikes" tabindex="-1"><a href="https://www.reuters.com/world/middle-east/gulf-bourses-subdued-us-iran-exchange-strikes-2026-07-12/" target="_blank" rel="noreferrer">Gulf bourses subdued as US and Iran exchange strikes</a> <a class="header-anchor" href="#gulf-bourses-subdued-as-us-and-iran-exchange-strikes" aria-label="Permalink to &quot;[Gulf bourses subdued as US and Iran exchange strikes](https://www.reuters.com/world/middle-east/gulf-bourses-subdued-us-iran-exchange-strikes-2026-07-12/)&quot;">​</a></h3><ul><li><strong>作者或机构：</strong> Ateeq Shariff</li><li><strong>来源媒体：</strong> Reuters</li><li><strong>发布时间：</strong> 2026-07-12 13:06 UTC（上海时间 21:06）</li><li><strong>核心观点：</strong> 尽管美伊相互发动导弹与无人机袭击，沙特和卡塔尔股市仅小幅上涨约0.1%，沙特阿美亦小幅走高。沙特正研究扩大通往红海的原油管道能力，以降低对霍尔木兹海峡的依赖。埃及股市小幅下跌，同时其一季度经常账户赤字同比显著扩大。</li><li><strong>为什么值得阅读：</strong> 海湾股市并未出现恐慌性下跌，说明区域资产仍在区分短期军事升级与长期能源运输中断；同时，替代运输基础设施可能改变冲突风险溢价的持续时间。</li><li><strong>市场与策略影响：</strong> 能源出口国股票可能因油价上涨获得部分对冲，而能源进口国及经常账户脆弱经济体更易承压。区域配置应重点区分能源净出口、财政缓冲和外部融资需求。</li></ul><h3 id="indian-rupee-and-bonds-likely-to-track-mideast-developments-inflation-data" tabindex="-1"><a href="https://www.reuters.com/world/india/indian-rupee-bonds-likely-track-mideast-developments-inflation-data-2026-07-13/" target="_blank" rel="noreferrer">Indian rupee and bonds likely to track Mideast developments, inflation data</a> <a class="header-anchor" href="#indian-rupee-and-bonds-likely-to-track-mideast-developments-inflation-data" aria-label="Permalink to &quot;[Indian rupee and bonds likely to track Mideast developments, inflation data](https://www.reuters.com/world/india/indian-rupee-bonds-likely-track-mideast-developments-inflation-data-2026-07-13/)&quot;">​</a></h3><ul><li><strong>作者或机构：</strong> Dharamraj Dhutia、Jaspreet Kalra</li><li><strong>来源媒体：</strong> Reuters</li><li><strong>发布时间：</strong> 2026-07-13 01:32 UTC（上海时间 09:32）</li><li><strong>核心观点：</strong> 印度卢比与国债将同时受到中东冲突、油价和印度及美国通胀数据影响。市场预计印度6月CPI可能16个月来首次突破央行4%的中期目标；油价上涨将对卢比和债券形成压力，美元走强也可能限制亚洲货币反弹。</li><li><strong>为什么值得阅读：</strong> 印度是观察能源进口型新兴市场如何吸收外部油价冲击的典型案例，文章同时覆盖汇率、债券、通胀和跨境资金流。</li><li><strong>市场与策略影响：</strong> 若油价维持高位，做多美元兑能源进口国货币、减持其久期资产的交易逻辑可能强化；但外资流入、指数纳入预期及央行干预会提高单边交易的尾部风险。</li></ul><h2 id="跨市场联动" tabindex="-1">跨市场联动 <a class="header-anchor" href="#跨市场联动" aria-label="Permalink to &quot;跨市场联动&quot;">​</a></h2><p>当前最清晰的传导链路为：</p><p><strong>海湾冲突升级 → 霍尔木兹通行风险上升 → 原油上涨 → 通胀预期回升 → 美联储加息概率上升 → 国债收益率和美元走强 → 高久期成长股及亚洲风险资产承压。</strong></p><p>这一链路与典型衰退型风险厌恶不同。黄金在本轮早盘交易中并未随地缘风险上涨，反而受到美元和收益率上升压制，说明“避险资产”内部出现明显分化。对系统化组合而言，关键不是简单增加避险资产，而是识别冲击属于需求衰退、金融压力还是供给型通胀。</p><h2 id="重要变化与延续性记录" tabindex="-1">重要变化与延续性记录 <a class="header-anchor" href="#重要变化与延续性记录" aria-label="Permalink to &quot;重要变化与延续性记录&quot;">​</a></h2><blockquote><p>由于仓库中未找到最近3至7篇同系列日报，本期作为连续性记录的初始基线；“延续趋势”主要依据当前24小时窗口内的多篇交叉核验结果。</p></blockquote><table tabindex="0"><thead><tr><th>板块</th><th>今日新增变化</th><th>延续趋势</th><th>是否反转</th><th>后续观察指标</th></tr></thead><tbody><tr><td>金融市场</td><td>油价、美元与美债收益率同步上行，亚洲股票和美股期货下跌</td><td>地缘风险继续主导跨资产定价</td><td>暂无明确反转</td><td>霍尔木兹实际船运量、布伦特原油、10年期美债收益率、VIX</td></tr><tr><td>宏观经济</td><td>市场提高年内多次加息概率</td><td>能源价格向通胀和政策预期传导</td><td>尚未反转</td><td>美国CPI、PPI、Warsh国会证词、通胀互换</td></tr><tr><td>量化交易</td><td>相关性结构切换为“油、美元、收益率同涨”</td><td>周末跳跃风险与跨市场高相关延续</td><td>常规股债对冲关系阶段性失效</td><td>股债滚动相关性、原油隐含波动率、开盘滑点、半导体跨市场领先关系</td></tr><tr><td>美股</td><td>纳指期货跌幅大于标普期货</td><td>AI盈利主线仍在，但估值受利率制约</td><td>未形成趋势反转</td><td>银行财报、科技盈利指引、实际利率、半导体指数</td></tr><tr><td>全球股票市场</td><td>亚洲股市承压，海湾股市相对稳定</td><td>能源出口国与进口国表现分化</td><td>暂无全面反转</td><td>亚洲货币、印度通胀、韩国半导体、海湾能源基础设施</td></tr></tbody></table><h2 id="未来24小时观察清单" tabindex="-1">未来24小时观察清单 <a class="header-anchor" href="#未来24小时观察清单" aria-label="Permalink to &quot;未来24小时观察清单&quot;">​</a></h2><ol><li>霍尔木兹海峡是否出现可验证的航运恢复或进一步中断。</li><li>布伦特原油能否站稳每桶78—80美元区域，以及原油期限结构是否进一步走向近月升水。</li><li>美国CPI公布前，联邦基金期货是否继续上调年内加息次数。</li><li>美元指数与10年期美债收益率是否继续同向上行；若出现背离，可能意味着市场开始从通胀交易切换至增长担忧。</li><li>纳斯达克期货相对标普500期货的弱势是否扩大。</li><li>韩国半导体板块能否止跌，以及其波动是否向美国芯片股扩散。</li><li>印度CPI、卢比与国债收益率对油价冲击的实际反应。</li><li>美联储主席 Kevin Warsh 国会证词前的政策预期调整。</li></ol><h2 id="来源索引" tabindex="-1">来源索引 <a class="header-anchor" href="#来源索引" aria-label="Permalink to &quot;来源索引&quot;">​</a></h2><ol><li><a href="https://www.reuters.com/business/media-telecom/global-markets-global-markets-2026-07-13/" target="_blank" rel="noreferrer">Shares slip in Asia as oil jumps on Gulf attacks</a> — Reuters，Wayne Cole，2026-07-13 00:25 UTC。</li><li><a href="https://www.reuters.com/world/asia-pacific/dollar-jumps-renewed-middle-east-attacks-hormuz-closure-2026-07-13/" target="_blank" rel="noreferrer">Dollar jumps on renewed Middle East attacks, Hormuz closure</a> — Reuters，Gregor Stuart Hunter，2026-07-13 00:29 UTC。</li><li><a href="https://www.reuters.com/world/middle-east/gulf-bourses-subdued-us-iran-exchange-strikes-2026-07-12/" target="_blank" rel="noreferrer">Gulf bourses subdued as US and Iran exchange strikes</a> — Reuters，Ateeq Shariff，2026-07-12 13:06 UTC。</li><li><a href="https://www.reuters.com/world/india/indian-rupee-bonds-likely-track-mideast-developments-inflation-data-2026-07-13/" target="_blank" rel="noreferrer">Indian rupee and bonds likely to track Mideast developments, inflation data</a> — Reuters，Dharamraj Dhutia、Jaspreet Kalra，2026-07-13 01:32 UTC。</li></ol><h2 id="免责声明" tabindex="-1">免责声明 <a class="header-anchor" href="#免责声明" aria-label="Permalink to &quot;免责声明&quot;">​</a></h2><p>本文仅用于信息整理、市场研究与交易系统开发参考，不构成任何投资建议、交易邀约或收益承诺。市场数据和新闻可能在发布后继续更新；任何投资或交易决策均应结合独立研究、实时数据、风险承受能力与合规要求。</p>',35)])])}const m=t(l,[["render",i]]);export{g as __pageData,m as default};
